def parse_amount(a):
    try:
        if isinstance(a, (int, float)):
            return int(a)
        s = str(a).replace(',','').strip()
        if s.isdigit():
            return int(s)
        if '.' in s:
            return int(float(s))
    except:
        return None
    return None

